    const formData = new FormData(e.currentTarget);
    saveMessage({
      name: 'Quick Hire Inquiry',
      phone: formData.get('phone') as string,
      content: formData.get('message') as string,
      type: 'Direct'
    });
    setShowHireModal(false);
