import React, { useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Float, Sphere, MeshDistortMaterial, Environment, ContactShadows } from '@react-three/drei';
import * as THREE from 'three';

// Define Three.js components as constants to avoid JSX.IntrinsicElements type errors
const Group = 'group' as any;
const AmbientLight = 'ambientLight' as any;
const PointLight = 'pointLight' as any;
const SpotLight = 'spotLight' as any;

const SceneContent = () => {
  const groupRef = useRef<THREE.Group>(null);

  useFrame((state) => {
    const t = state.clock.getElapsedTime();
    if (groupRef.current) {
      groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, Math.cos(t / 4) / 10, 0.05);
      groupRef.current.rotation.y = THREE.MathUtils.lerp(groupRef.current.rotation.y, Math.sin(t / 8) / 10, 0.05);
    }
  });

  return (
    // Use the defined Group component to avoid intrinsic element type errors
    <Group ref={groupRef}>
      <Float speed={2} rotationIntensity={0.5} floatIntensity={1}>
        <Sphere args={[1.5, 64, 64]} position={[-7, 4, -5]}>
          <MeshDistortMaterial color="#E6E6FA" speed={3} distort={0.4} roughness={0.1} metalness={0.2} />
        </Sphere>
      </Float>

      <Float speed={1.5} rotationIntensity={0.3} floatIntensity={2}>
        <Sphere args={[2.5, 64, 64]} position={[8, -3, -12]}>
          <MeshDistortMaterial color="#FFDAB9" speed={2} distort={0.3} roughness={0.1} />
        </Sphere>
      </Float>

      <Float speed={3} rotationIntensity={1} floatIntensity={1.5}>
        <Sphere args={[1, 64, 64]} position={[0, -8, -6]}>
          <MeshDistortMaterial color="#FFFDD0" speed={4} distort={0.5} roughness={0.1} />
        </Sphere>
      </Float>

      {/* Use Uppercase component constants for lights to resolve JSX namespace errors */}
      <AmbientLight intensity={0.6} />
      <PointLight position={[20, 30, 10]} intensity={1.5} />
      <SpotLight position={[-20, 30, 10]} angle={0.2} penumbra={1} intensity={1} />
      <ContactShadows opacity={0.4} scale={20} blur={2.4} far={20} />
      <Environment preset="studio" />
    </Group>
  );
};

const ThreeBackground: React.FC = () => {
  return (
    <div className="fixed inset-0 -z-10 bg-[#fdfaf7]">
      <Canvas 
        camera={{ position: [0, 0, 15], fov: 45 }} 
        dpr={[1, 2]}
        gl={{ antialias: true, alpha: true }}
      >
        <SceneContent />
      </Canvas>
    </div>
  );
};

