  // Sync to Cloud: Admin function to make changes global
  const syncToCloud = async (currentHero: string[], currentArt: ArtWork[], currentMsgs: Message[]) => {
    if (!isAdmin) return;
    setIsSyncing(true);
    try {
      await fetch(CLOUD_API_BASE, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ heroImages: currentHero, artGallery: currentArt, messages: currentMsgs }),
      });
      setStatusMsg({ text: 'Site Updated Globally!', type: 'success' });
      setTimeout(() => setStatusMsg(null), 3000);
    } catch (err) {
      alert("Global sync failed. Check your internet connection.");
    } finally {
      setIsSyncing(false);
    }
  };

  const [currentHeroIndex, setCurrentHeroIndex] = useState(0);
