              <input required value={username} onChange={e => setUsername(e.target.value)} placeholder="Username" className="w-full glass bg-white/50 p-4 rounded-2xl outline-none" />
              <input required value={password} onChange={e => setPassword(e.target.value)} type="password" placeholder="Password" className="w-full glass bg-white/50 p-4 rounded-2xl outline-none" />
              <button className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold">SIGN IN</button>
            </form>
          </motion.div>
        </div>
      )}</AnimatePresence>

      {/* Hire Modal */}
      <AnimatePresence>{showHireModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center px-6">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setShowHireModal(false)} />
          <motion.div initial={{ y: 50, opacity: 0 }} animate={{ y: 0, opacity: 1 }} className="relative glass p-10 rounded-[48px] max-w-lg w-full border border-white">
            <h2 className="text-4xl font-serif font-bold mb-8">Hire Me</h2>
            <div className="space-y-4">
              <a href={`tel:${PERSONAL_INFO.phone}`} className="flex items-center gap-4 p-6 bg-green-500 text-white rounded-3xl shadow-xl font-bold"><Phone size={24} /> Call Direct: {PERSONAL_INFO.phone}</a>
              <form onSubmit={(e) => { e.preventDefault(); const f = e.currentTarget; saveMessage({ name: 'Direct Hire', phone: (f.elements.namedItem('ph') as HTMLInputElement).value, content: (f.elements.namedItem('msg') as HTMLTextAreaElement).value, type: 'Direct' }); setShowHireModal(false); }} className="space-y-4 pt-4 border-t border-slate-200">
                <input name="ph" required placeholder="Your Phone Number" className="w-full glass bg-white/50 p-4 rounded-2xl" />
                <textarea name="msg" required placeholder="Tuition details (Class, Location, Subjects)..." className="w-full glass bg-white/50 p-4 rounded-2xl h-24" />
                <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold">REQUEST TUITION</button>
              </form>
            </div>
          </motion.div>
        </div>
      )}</AnimatePresence>

      <footer className="py-20 border-t bg-white/30 backdrop-blur-sm text-center">
        <div className="text-3xl font-serif font-bold text-slate-900 mb-4 uppercase tracking-widest">M. Zaman</div>
        <p className="text-slate-400 text-sm font-medium">&copy; 2024 Maisha Zaman. Economics Scholar & Fabric Artist.</p>
      </footer>
    </div>
  );
};

