  const pushGlobalUpdate = async (hero: string[], art: ArtWork[], msgs: Message[]) => {
    setIsSyncing(true);
    try {
      // First, get the latest state from cloud to avoid overwriting recent comments from others
      const response = await fetch(CLOUD_SYNC_URL);
      let latestMsgs = msgs;
      let latestArt = art;

      if (response.ok) {
        const cloudData = await response.json();
        // Merge strategy: Keep current hero images (Admin choice), 
        // but merge new messages/comments that might have arrived
        const cloudMsgs = cloudData.messages || [];
        const combinedMsgs = [...msgs];
        cloudMsgs.forEach((cm: Message) => {
          if (!combinedMsgs.find(m => m.id === cm.id)) combinedMsgs.push(cm);
        });
        latestMsgs = combinedMsgs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
      }

      await fetch(CLOUD_SYNC_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ heroImages: hero, artGallery: latestArt, messages: latestMsgs }),
      });

      setMessages(latestMsgs);
      setArtGallery(latestArt);

      if (isAdmin) {
        setStatusMsg({ text: 'Changes Published Globally!', type: 'success' });
        setTimeout(() => setStatusMsg(null), 3000);
      }
    } catch (err) {
      console.error("Global Sync Failed:", err);
    } finally {
      setIsSyncing(false);
    }
  };

