  const [view, setView] = useState<'home' | 'gallery'>('home');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isInitialLoad, setIsInitialLoad] = useState(true);

  // --- GLOBAL STATE ---
  const [messages, setMessages] = useState<Message[]>([]);
  const [heroImages, setHeroImages] = useState<string[]>(["https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?auto=format&fit=crop&q=80&w=600"]);
  const [artGallery, setArtGallery] = useState<ArtWork[]>([
    { id: '1', url: 'https://images.unsplash.com/photo-1541701494587-cb58502866ab?q=80&w=600', title: 'Blue Lotus', description: 'Hand-painted on pure silk.', comments: [] },
    { id: '2', url: 'https://images.unsplash.com/photo-1456735190827-d1262f71b8a3?q=80&w=600', title: 'Golden Strokes', description: 'Acrylic fabric painting experiment.', comments: [] },
    { id: '3', url: 'https://images.unsplash.com/photo-1513364776144-60967b0f800f?q=80&w=600', title: 'Abstract Crimson', description: 'Cotton dupatta design.', comments: [] }
  ]);

  // Initial Fetch: Load permanent data from Cloud for everyone
  useEffect(() => {
    const fetchCloudData = async () => {
      try {
        const response = await fetch(CLOUD_SYNC_URL);
        if (response.ok) {
          const data = await response.json();
          if (data.heroImages) setHeroImages(data.heroImages);
          if (data.artGallery) setArtGallery(data.artGallery);
          if (data.messages) setMessages(data.messages);
        }
      } catch (err) {
        console.warn("Sync fetch failed, using internal defaults.");
      } finally {
        setIsInitialLoad(false);
      }
    };
    fetchCloudData();
  }, []);

  // Sync to Cloud: Robust merge function to ensure data permanence
  const pushGlobalUpdate = async (hero: string[], art: ArtWork[], msgs: Message[]) => {
    setIsSyncing(true);
    try {
      // First, get the latest state from cloud to avoid overwriting recent comments from others
      const response = await fetch(CLOUD_SYNC_URL);
      let latestMsgs = msgs;
      let latestArt = art;

      if (response.ok) {
        const cloudData = await response.json();
        // Merge strategy: Keep current hero images (Admin choice), 
        // but merge new messages/comments that might have arrived
        const cloudMsgs = cloudData.messages || [];
        const combinedMsgs = [...msgs];
        cloudMsgs.forEach((cm: Message) => {
          if (!combinedMsgs.find(m => m.id === cm.id)) combinedMsgs.push(cm);
        });
        latestMsgs = combinedMsgs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
      }

      await fetch(CLOUD_SYNC_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ heroImages: hero, artGallery: latestArt, messages: latestMsgs }),
      });

      setMessages(latestMsgs);
      setArtGallery(latestArt);

      if (isAdmin) {
        setStatusMsg({ text: 'Changes Published Globally!', type: 'success' });
        setTimeout(() => setStatusMsg(null), 3000);
      }
    } catch (err) {
      console.error("Global Sync Failed:", err);
    } finally {
      setIsSyncing(false);
    }
  };

  const [currentHeroIndex, setCurrentHeroIndex] = useState(0);
