  const [isSyncing, setIsSyncing] = useState(false);
  const [currentHeroIndex, setCurrentHeroIndex] = useState(0);
  const [statusMsg, setStatusMsg] = useState<{ text: string, type: 'success' | 'error' } | null>(null);

  // --- PERSISTENT STATE ---
  const [messages, setMessages] = useState<Message[]>([]);
  const [heroImages, setHeroImages] = useState<string[]>(["https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?auto=format&fit=crop&q=80&w=600"]);
  const [artGallery, setArtGallery] = useState<ArtWork[]>([
    { id: '1', url: 'https://images.unsplash.com/photo-1541701494587-cb58502866ab?q=80&w=600', title: 'Blue Lotus', description: 'Hand-painted on pure silk.', comments: [] },
    { id: '2', url: 'https://images.unsplash.com/photo-1456735190827-d1262f71b8a3?q=80&w=600', title: 'Golden Strokes', description: 'Acrylic fabric painting experiment.', comments: [] },
    { id: '3', url: 'https://images.unsplash.com/photo-1513364776144-60967b0f800f?q=80&w=600', title: 'Abstract Crimson', description: 'Cotton dupatta design.', comments: [] }
  ]);

  // Initial Data Fetch: Connect to "m-zaman-qrpm-blob" logic
  useEffect(() => {
    const fetchBlobData = async () => {
      try {
        const response = await fetch(VERCEL_BLOB_STORE_URL);
        if (response.ok) {
          const data = await response.json();
          if (data.heroImages) setHeroImages(data.heroImages);
          if (data.artGallery) setArtGallery(data.artGallery);
          if (data.messages) setMessages(data.messages);
        }
      } catch (err) {
        console.warn("Vercel Blob Sync Unavailable. Using local state.");
      }
    };
    fetchBlobData();
  }, []);

  // Intelligent Sync: Fetch current cloud data, merge new entries, and push back
  const syncToBlob = async (hero: string[], art: ArtWork[], msgs: Message[]) => {
    setIsSyncing(true);
    try {
      // Intelligent Merge: Ensure visitor messages are preserved
      const latestResponse = await fetch(VERCEL_BLOB_STORE_URL);
      let mergedMsgs = msgs;
      let mergedArt = art;

      if (latestResponse.ok) {
        const cloudData = await latestResponse.json();

        // Merge Messages (Admin deletes stay deleted, but new visitor messages from elsewhere are kept)
        const cloudMsgs = cloudData.messages || [];
        const combinedMsgs = [...msgs];
        cloudMsgs.forEach((cm: Message) => {
          if (!combinedMsgs.find(m => m.id === cm.id) && isAdmin === false) {
             combinedMsgs.push(cm);
          }
        });
        mergedMsgs = combinedMsgs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

        // Merge Comments for art
        mergedArt = art.map(localArt => {
           const cloudArt = cloudData.artGallery?.find((a: ArtWork) => a.id === localArt.id);
           if (cloudArt) {
             const combinedComments = [...(localArt.comments || [])];
             cloudArt.comments?.forEach((cc: Comment) => {
               if (!combinedComments.find(c => c.text === cc.text && c.date === cc.date)) {
                 combinedComments.push(cc);
               }
             });
             return { ...localArt, comments: combinedComments };
           }
           return localArt;
        });
      }

      await fetch(VERCEL_BLOB_STORE_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ heroImages: hero, artGallery: mergedArt, messages: mergedMsgs }),
      });

      setMessages(mergedMsgs);
      setArtGallery(mergedArt);

      if (isAdmin) {
        setStatusMsg({ text: 'Blob Successfully Synchronized', type: 'success' });
        setTimeout(() => setStatusMsg(null), 3000);
      }
    } catch (err) {
      console.error("Blob Sync Error:", err);
    } finally {
      setIsSyncing(false);
    }
  };

