  const [isAiLoading, setIsAiLoading] = useState(false);
  const [isUploading, setIsUploading] = useState(false);

  // Core Data State
  const [messages, setMessages] = useState<Message[]>([]);
  const [heroImages, setHeroImages] = useState<string[]>(["https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?auto=format&fit=crop&q=80&w=600"]);
  const [artGallery, setArtGallery] = useState<ArtWork[]>([
    { id: '1', url: 'https://images.unsplash.com/photo-1541701494587-cb58502866ab?q=80&w=600', title: 'Blue Lotus', description: 'Hand-painted on pure silk.', comments: [] },
    { id: '2', url: 'https://images.unsplash.com/photo-1456735190827-d1262f71b8a3?q=80&w=600', title: 'Golden Strokes', description: 'Acrylic fabric painting experiment.', comments: [] },
    { id: '3', url: 'https://images.unsplash.com/photo-1513364776144-60967b0f800f?q=80&w=600', title: 'Abstract Crimson', description: 'Cotton dupatta design.', comments: [] }
  ]);

  const [currentHeroIndex, setCurrentHeroIndex] = useState(0);
  const [statusMsg, setStatusMsg] = useState<{ text: string, type: 'success' | 'error' } | null>(null);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [adminTab, setAdminTab] = useState<'messages' | 'settings'>('messages');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const artDescRef = useRef<HTMLTextAreaElement>(null);
  const artTitleRef = useRef<HTMLInputElement>(null);

  // Fetch initial data from Supabase
  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    // 1. Fetch Messages
    const { data: msgs, error: msgErr } = await supabase
      .from('messages')
      .select('*')
      .order('timestamp', { ascending: false });
    if (msgs) setMessages(msgs);

    // 2. Fetch Art Gallery
    const { data: arts, error: artErr } = await supabase
      .from('art_gallery')
      .select('*')
      .order('created_at', { ascending: false });
    if (arts && arts.length > 0) setArtGallery(arts);

    // 3. Fetch Hero Images (Assuming a simple table for this)
    const { data: heros, error: heroErr } = await supabase
      .from('hero_settings')
      .select('image_url');
    if (heros && heros.length > 0) setHeroImages(heros.map(h => h.image_url));
  };

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    if (heroImages.length > 1) {
      const interval = setInterval(() => {
        setCurrentHeroIndex((prev) => (prev + 1) % heroImages.length);
      }, 5000);
      return () => clearInterval(interval);
    }
  }, [heroImages]);

  const generateAiDescription = async () => {
    const title = artTitleRef.current?.value;
    if (!title) {
      alert("Please enter a title first.");
      return;
    }

    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Act as a creative fabric art critic. Write a poetic, one-sentence description for a piece of fabric art titled "${title}". Keep it under 20 words. Focus on texture, emotion, and craftsmanship.`,
      });
      if (artDescRef.current) {
        artDescRef.current.value = response.text || "";
      }
    } catch (error) {
      console.error("AI Generation Error:", error);
    } finally {
      setIsAiLoading(false);
    }
  };

  const saveMessage = async (msg: Omit<Message, 'id' | 'timestamp'>) => {
    const { data, error } = await supabase
      .from('messages')
      .insert([{ 
        name: msg.name, 
        phone: msg.phone, 
        content: msg.content, 
        type: msg.type 
      }])
      .select();

    if (!error) {
      fetchData(); // Refresh messages
      setStatusMsg({ text: 'Message delivered', type: 'success' });
      setTimeout(() => setStatusMsg(null), 4000);
    } else {
      setStatusMsg({ text: 'Error sending message', type: 'error' });
      setTimeout(() => setStatusMsg(null), 4000);
    }
  };

  const deleteMessage = async (id: string) => {
    const { error } = await supabase
      .from('messages')
      .delete()
      .eq('id', id);
    if (!error) fetchData();
  };

  const addHeroImage = async (url: string) => {
    if (heroImages.length >= 5) {
      alert("Maximum 5 hero images allowed.");
      return;
    }
    const { error } = await supabase
      .from('hero_settings')
      .insert([{ image_url: url }]);

    if (!error) {
      fetchData();
      setStatusMsg({ text: 'Hero Image Added', type: 'success' });
      setTimeout(() => setStatusMsg(null), 3000);
    }
  };

  const removeHeroImage = async (url: string) => {
    if (heroImages.length <= 1) {
      alert("At least one hero image is required.");
      return;
    }
    const { error } = await supabase
      .from('hero_settings')
      .delete()
      .eq('image_url', url);
    if (!error) {
      fetchData();
      setCurrentHeroIndex(0);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, target: 'hero' | 'gallery') => {
    const file = e.target.files?.[0];
    if (file) {
      setIsUploading(true);
      const fileName = `${Date.now()}-${file.name}`;
      const { data, error } = await supabase.storage
        .from('portfolio-images')
        .upload(`${target}/${fileName}`, file);

      if (data) {
        const { data: publicUrlData } = supabase.storage
          .from('portfolio-images')
          .getPublicUrl(`${target}/${fileName}`);

        const publicUrl = publicUrlData.publicUrl;

        if (target === 'hero') {
          await addHeroImage(publicUrl);
        } else {
          // If gallery, we might want to store it temporarily or wait for the form submit
          if (artTitleRef.current) {
            const title = artTitleRef.current.value || 'Untitled';
            const desc = artDescRef.current?.value || '';
            await addArt(publicUrl, title, desc);
          }
        }
      }
      setIsUploading(false);
    }
  };

  const addArt = async (url: string, title: string, desc: string) => {
    const { error } = await supabase
      .from('art_gallery')
      .insert([{ url, title, description: desc, comments: [] }]);

    if (!error) {
      fetchData();
      setStatusMsg({ text: 'New Art Uploaded', type: 'success' });
      setTimeout(() => setStatusMsg(null), 3000);
    }
  };

  const deleteArt = async (id: string) => {
    const { error } = await supabase
      .from('art_gallery')
      .delete()
      .eq('id', id);
    if (!error) fetchData();
  }

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username === 'M. ZAMAN' && password === 'M121213') {
      setIsAdmin(true);
      setShowLoginModal(false);
      setUsername('');
      setPassword('');
    } else {
      alert('Invalid Credentials');
    }
  };

  const handleHireSubmit = (e: React.FormEvent<HTMLFormElement>) => {
