  build: {
    outDir: 'dist',
    sourcemap: false
  }
});

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  BookOpen, Palette, GraduationCap, MapPin, Phone, Mail, 
  Facebook, User, Calendar, Briefcase, Clock, DollarSign, 
  ExternalLink, MessageCircle, Heart, Star, Brush, X, Trash2, LogOut, CheckCircle, ShieldCheck, Award, Zap, Verified, Plus, ArrowLeft, Send, Image as ImageIcon, Upload, Sparkles, Loader2
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { createClient } from '@supabase/supabase-js';
import ThreeBackground from './components/ThreeBackground';
import GlassCard from './components/GlassCard';
import { SERVICES, EDUCATION, SOCIALS, LOCATIONS, PERSONAL_INFO } from './constants';
import { Message, ArtWork, Comment } from './types';

// Supabase Initialization
const supabaseUrl = process.env.SUPABASE_URL || '';
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || '';
const supabase = (supabaseUrl && supabaseAnonKey) ? createClient(supabaseUrl, supabaseAnonKey) : null;

const App: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [showHireModal, setShowHireModal] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [view, setView] = useState<'home' | 'gallery'>('home');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [isUploading, setIsUploading] = useState(false);

  // Core Data State
  const [messages, setMessages] = useState<Message[]>([]);
  const [heroImages, setHeroImages] = useState<string[]>(["https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?auto=format&fit=crop&q=80&w=600"]);
  const [artGallery, setArtGallery] = useState<ArtWork[]>([
    { id: '1', url: 'https://images.unsplash.com/photo-1541701494587-cb58502866ab?q=80&w=600', title: 'Blue Lotus', description: 'Hand-painted on pure silk.', comments: [] },
    { id: '2', url: 'https://images.unsplash.com/photo-1456735190827-d1262f71b8a3?q=80&w=600', title: 'Golden Strokes', description: 'Acrylic fabric painting experiment.', comments: [] },
    { id: '3', url: 'https://images.unsplash.com/photo-1513364776144-60967b0f800f?q=80&w=600', title: 'Abstract Crimson', description: 'Cotton dupatta design.', comments: [] }
  ]);

  const [currentHeroIndex, setCurrentHeroIndex] = useState(0);
  const [statusMsg, setStatusMsg] = useState<{ text: string, type: 'success' | 'error' } | null>(null);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [adminTab, setAdminTab] = useState<'messages' | 'settings'>('messages');

  const heroFileInputRef = useRef<HTMLInputElement>(null);
  const artFileInputRef = useRef<HTMLInputElement>(null);
  const artDescRef = useRef<HTMLTextAreaElement>(null);
  const artTitleRef = useRef<HTMLInputElement>(null);

  // Fetch initial data from Supabase
  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    if (!supabase) return;

    try {
      // 1. Fetch Messages
      const { data: msgs } = await supabase
        .from('messages')
        .select('*')
        .order('timestamp', { ascending: false });
      if (msgs) setMessages(msgs);

      // 2. Fetch Art Gallery
      const { data: arts } = await supabase
        .from('art_gallery')
        .select('*')
        .order('id', { ascending: false });
      if (arts && arts.length > 0) setArtGallery(arts);

      // 3. Fetch Hero Settings (e.g., image rotation)
      const { data: heros } = await supabase
        .from('hero_images')
        .select('url');
      if (heros && heros.length > 0) setHeroImages(heros.map(h => h.url));
    } catch (err) {
      console.error("Fetch Error:", err);
    }
  };

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    if (heroImages.length > 1) {
      const interval = setInterval(() => {
        setCurrentHeroIndex((prev) => (prev + 1) % heroImages.length);
      }, 5000);
      return () => clearInterval(interval);
    }
  }, [heroImages]);

  // AI Feature: Generate Art Description
  const generateAiDescription = async () => {
    const title = artTitleRef.current?.value;
    if (!title) {
      alert("Please enter a title first.");
      return;
    }

    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Act as a creative fabric art critic. Write a poetic, one-sentence description for a piece of fabric art titled "${title}". Keep it under 20 words. Focus on texture, emotion, and craftsmanship.`,
      });
      if (artDescRef.current) {
        artDescRef.current.value = response.text || "";
      }
    } catch (error) {
      console.error("AI Generation Error:", error);
    } finally {
      setIsAiLoading(false);
    }
  };

  const saveMessage = async (msg: Omit<Message, 'id' | 'timestamp'>) => {
    if (!supabase) return;
    const { error } = await supabase
      .from('messages')
      .insert([{ ...msg, timestamp: new Date().toLocaleString() }]);

    if (!error) {
      fetchData();
      setStatusMsg({ text: 'Message delivered', type: 'success' });
      setTimeout(() => setStatusMsg(null), 4000);
    }
  };

  const deleteMessage = async (id: string) => {
    if (!supabase) return;
    const { error } = await supabase.from('messages').delete().eq('id', id);
    if (!error) fetchData();
  };

  const addHeroImage = async (url: string) => {
    if (!supabase) return;
    if (heroImages.length >= 5) {
      alert("Maximum 5 hero images allowed.");
      return;
    }
    const { error } = await supabase.from('hero_images').insert([{ url }]);
    if (!error) fetchData();
  };

  const removeHeroImage = async (url: string) => {
    if (!supabase) return;
    if (heroImages.length <= 1) {
      alert("At least one hero image is required.");
      return;
    }
    const { error } = await supabase.from('hero_images').delete().eq('url', url);
    if (!error) {
      fetchData();
      setCurrentHeroIndex(0);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, target: 'hero' | 'gallery') => {
    if (!supabase) return;
    const file = e.target.files?.[0];
    if (file) {
      setIsUploading(true);
      try {
        const filePath = `${target}/${Date.now()}-${file.name}`;
        const { error: uploadError } = await supabase.storage
          .from('portfolio-assets')
          .upload(filePath, file);

        if (uploadError) throw uploadError;

        const { data: publicUrlData } = supabase.storage
          .from('portfolio-assets')
          .getPublicUrl(filePath);

        if (target === 'hero') {
          await addHeroImage(publicUrlData.publicUrl);
        } else {
          // Store temp URL for preview or handled in addArt
          if (artTitleRef.current) {
            await addArt(publicUrlData.publicUrl, artTitleRef.current.value || 'Untitled', artDescRef.current?.value || '');
          }
        }
      } catch (err) {
        console.error("Upload Error:", err);
      } finally {
        setIsUploading(false);
      }
    }
  };

  const addArt = async (url: string, title: string, desc: string) => {
    if (!supabase) return;
    const { error } = await supabase
      .from('art_gallery')
      .insert([{ url, title, description: desc, comments: [] }]);

    if (!error) {
      fetchData();
      setStatusMsg({ text: 'New Art Uploaded', type: 'success' });
      setTimeout(() => setStatusMsg(null), 3000);
    }
  };

  const deleteArt = async (id: string) => {
    if (!supabase) return;
    const { error } = await supabase.from('art_gallery').delete().eq('id', id);
    if (!error) fetchData();
  }

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username === 'M. ZAMAN' && password === 'M121213') {
      setIsAdmin(true);
      setShowLoginModal(false);
      setUsername('');
      setPassword('');
    } else {
      alert('Invalid Credentials');
    }
  };

  const handleHireSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    saveMessage({
      name: 'Quick Hire Inquiry',
      phone: formData.get('phone') as string,
      content: formData.get('message') as string,
      type: 'Direct'
    });
    setShowHireModal(false);
  };

  const handleContactSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    saveMessage({
      name: formData.get('name') as string,
      phone: formData.get('phone') as string,
      content: formData.get('inquiry') as string,
      type: 'Inquiry'
    });
    e.currentTarget.reset();
  };

  if (isAdmin) {
    return (
      <div className="min-h-screen relative text-slate-800 bg-[#fdfaf7] selection:bg-purple-200">
        <ThreeBackground />
        <nav className="fixed top-0 w-full z-50 glass py-4 shadow-sm">
          <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
            <div className="text-2xl font-serif font-bold text-purple-600 flex items-center gap-2">
               <ShieldCheck size={28} />
               <span>ADMIN PORTAL</span>
            </div>
            <div className="flex items-center gap-4">
              <button 
                onClick={() => setAdminTab(adminTab === 'messages' ? 'settings' : 'messages')}
                className="px-4 py-2 glass rounded-xl text-xs font-bold uppercase tracking-widest text-slate-600"
              >
                {adminTab === 'messages' ? 'Manage Site' : 'View Messages'}
              </button>
              <button 
                onClick={() => setIsAdmin(false)} 
                className="flex items-center gap-2 px-6 py-2 bg-slate-900 text-white rounded-full font-bold text-xs tracking-widest hover:bg-slate-800 transition-all"
              >
                <LogOut size={16} /> LOGOUT
              </button>
            </div>
          </div>
        </nav>

        <main className="max-w-6xl mx-auto px-6 pt-32 pb-20">
          <AnimatePresence mode="wait">
            {adminTab === 'messages' ? (
              <motion.div key="msgs" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }}>
                <div className="mb-12">
                  <h1 className="text-5xl font-serif font-bold mb-2 text-slate-900">Message Inbox</h1>
                  <p className="text-slate-500 font-medium">Managing {messages.length} student inquiries.</p>
                </div>
                <div className="grid grid-cols-1 gap-6">
                  {messages.length === 0 ? (
                    <GlassCard className="text-center py-20"><p className="text-slate-400">No messages yet.</p></GlassCard>
                  ) : (
                    messages.map((msg) => (
                      <div key={msg.id} className="glass p-8 rounded-[32px] border border-white/50 shadow-xl flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                        <div className="flex-1">
                          <div className="flex items-center gap-3 mb-3">
                            <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${msg.type === 'Inquiry' ? 'bg-purple-100 text-purple-600' : 'bg-orange-100 text-orange-600'}`}>{msg.type}</span>
                            <span className="text-[10px] font-bold text-slate-400 flex items-center gap-1"><Clock size={12} /> {msg.timestamp}</span>
                          </div>
                          <h3 className="text-xl font-bold text-slate-900 mb-1">{msg.name}</h3>
                          <p className="text-purple-600 font-bold mb-4 flex items-center gap-2"><Phone size={14} /> {msg.phone}</p>
                          <div className="bg-white/40 p-5 rounded-2xl border border-white/60"><p className="text-slate-600 text-sm leading-relaxed">{msg.content}</p></div>
                        </div>
                        <button onClick={() => deleteMessage(msg.id)} className="p-4 bg-red-50 text-red-500 rounded-2xl hover:bg-red-500 hover:text-white transition-all"><Trash2 size={24} /></button>
                      </div>
                    ))
                  )}
                </div>
              </motion.div>
            ) : (
              <motion.div key="settings" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }} className="space-y-12">
                <div>
                  <h1 className="text-5xl font-serif font-bold mb-2">Site Management</h1>
                  <p className="text-slate-500">Update your visuals and gallery (Supabase Cloud).</p>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                  <GlassCard className="space-y-6">
                    <div className="flex items-center justify-between">
                       <div className="flex items-center gap-3 text-purple-600">
                          <ImageIcon size={24} />
                          <h3 className="text-xl font-bold">Homepage Visuals</h3>
                       </div>
                       <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{heroImages.length}/5 Images</span>
                    </div>
                    <div className="grid grid-cols-3 gap-4">
                      {heroImages.map((img, i) => (
                        <div key={i} className="relative aspect-[4/5] rounded-xl overflow-hidden group border border-slate-100 shadow-inner">
                           <img src={img} className="w-full h-full object-cover" />
                           <button 
                             onClick={() => removeHeroImage(img)}
                             className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-lg opacity-0 group-hover:opacity-100 transition-opacity"
                           >
                             <Trash2 size={12} />
                           </button>
                        </div>
                      ))}
                    </div>
                    <div className="space-y-4">
                      <input type="file" ref={heroFileInputRef} onChange={(e) => handleFileUpload(e, 'hero')} accept="image/*" className="hidden" />
                      <button onClick={() => heroFileInputRef.current?.click()} className="w-full glass border-2 border-dashed border-purple-200 py-4 rounded-2xl font-bold tracking-widest text-purple-600 flex items-center justify-center gap-2 hover:bg-purple-50 transition-all">
                        {isUploading ? <Loader2 size={18} className="animate-spin" /> : <Upload size={18} />} UPLOAD NEW HERO
                      </button>
                    </div>
                  </GlassCard>

                  <GlassCard className="space-y-6">
                    <div className="flex items-center justify-between mb-2">
                      <div className="flex items-center gap-3 text-orange-600">
                         <Palette size={24} />
                         <h3 className="text-xl font-bold">Add Art to Cloud</h3>
                      </div>
                      <button 
                        onClick={generateAiDescription}
                        disabled={isAiLoading}
                        className="flex items-center gap-2 px-3 py-1 bg-indigo-50 text-indigo-600 rounded-lg text-[10px] font-black uppercase tracking-widest border border-indigo-100 hover:bg-indigo-600 hover:text-white transition-all disabled:opacity-50"
                      >
                        {isAiLoading ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                        AI Visionary Describe
                      </button>
                    </div>
                    <form className="space-y-4" onSubmit={(e) => {
                      e.preventDefault();
                      const f = e.currentTarget;
                      const title = (f.elements.namedItem('arttitle') as HTMLInputElement).value;
                      const desc = (f.elements.namedItem('artdesc') as HTMLTextAreaElement).value;
                      if(title) {
                        artFileInputRef.current?.click();
                      }
                    }}>
                      <div className="grid grid-cols-1 gap-4">
                        <input ref={artTitleRef} name="arttitle" required placeholder="Art Title" className="glass bg-white/50 border border-slate-200 p-4 rounded-2xl outline-none" />
                      </div>
                      <textarea ref={artDescRef} name="artdesc" placeholder="Art description..." className="w-full glass bg-white/50 border border-slate-200 p-4 rounded-2xl outline-none h-24 resize-none" />
                      <input type="file" ref={artFileInputRef} onChange={(e) => handleFileUpload(e, 'gallery')} accept="image/*" className="hidden" />
                      <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold tracking-widest hover:bg-orange-500 transition-all flex items-center justify-center gap-2">
                        <Plus size={18} /> SELECT IMAGE & UPLOAD
                      </button>
                    </form>
                  </GlassCard>
                </div>

                <div className="mt-12">
                   <h3 className="text-2xl font-serif font-bold mb-6">Current Gallery ({artGallery.length})</h3>
                   <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                      {artGallery.map(art => (
                        <div key={art.id} className="relative aspect-square rounded-2xl overflow-hidden group border border-white">
                           <img src={art.url} className="w-full h-full object-cover" />
                           <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                              <button onClick={() => deleteArt(art.id)} className="p-3 bg-red-500 text-white rounded-full hover:scale-110 transition-transform">
                                <Trash2 size={20} />
                              </button>
                           </div>
                        </div>
                      ))}
                   </div>
                </div>
              </motion.div>
            )}
